    int n = blockIdx.x;
    int c = blockIdx.y * blockDim.y + threadIdx.y;
    int h = blockIdx.z * blockDim.z + threadIdx.z;

    if (c >= C || h >= H) return;

    float sum = 0.0f;
    for (int k = 0; k < K; ++k) {
        for (int r = 0; r < R; ++r) {
            for (int s = 0; s < S; ++s) {
