    int height_in, int width_in, int height_out, int width_out,
    int kernel_size, int stride, int padding, int output_padding,
    float scaling_factor) {
    int b = blockIdx.x;
    int oc = blockIdx.y;
    int oh = blockIdx.z;
    int ow = blockIdx.w;

    int ih_start = oh * stride - padding;
    int iw_start = ow * stride - padding;
    int ih_end = min(ih_start + kernel_size, height_in);
    int iw_end = min(iw_start + kernel_size, width_in);

    float sum = 0.0f;
    for (int ic = 0; ic < in_channels; ++ic) {
        for (int kh = ih_start; kh < ih_end; ++kh) {
            for (int kw = iw_start; kw < iw_end; ++kw) {
                int ih = kh - ih_start;
                int iw = kw - iw_start;
