# Define the custom CUDA kernel using TorchScript
custom_kernel_code = """
#include <torch/torch.h>

namespace {

__global__ void matmul_relu(float* A, float* B, float* C, int M, int N, int K) {
    const int row = blockIdx.y * blockDim.y + threadIdx.y;
    const int col = blockIdx.x * blockDim.x + threadIdx.x;

    if (row < M && col < N) {
        float sum = 0.0f;
        for (int k = 0; k < K; ++k) {
            sum += A[row * K + k] * B[k * N + col];
        }
        C[row * N + col] = max(sum, 0.0f);
    }
}

} // namespace

void matmul_relu_forward(torch::Tensor A, torch::Tensor B, torch::Tensor C) {
    const int M = A.size(0);
    const int N = B.size(1);
    const int K = A.size(1);

    dim3 grid((N + 255) / 256, (M + 255) / 256, 1);
    dim3 block(256, 1, 1);

    matmul_relu<<<grid, block>>>(A.data_ptr<float>(), B.data_ptr<float>(), C.data_ptr<float>(), M, N, K);
}
